import { PayloadSchema } from "./src/schema.ts";
import { type } from "arktype";

// Criterion 1: int branch morphs "42" string → 42 number
const r1 = PayloadSchema({ kind: "int", value: "42" });
console.assert(
  r1 !== null && typeof r1 === "object" && !("issues" in r1) &&
  r1.kind === "int" && r1.value === 42 && typeof r1.value === "number",
  "FAIL criterion 1"
);
console.log("✅ Criterion 1:", r1);

// Criterion 2: raw branch keeps "42" as string
const r2 = PayloadSchema({ kind: "raw", value: "42" });
console.assert(
  r2 !== null && typeof r2 === "object" && !("issues" in r2) &&
  r2.kind === "raw" && r2.value === "42" && typeof r2.value === "string",
  "FAIL criterion 2"
);
console.log("✅ Criterion 2:", r2);

// Criterion 3: unknown kind → ArkErrors
const r3 = PayloadSchema({ kind: "other", value: "42" });
console.assert(r3 instanceof type.errors, "FAIL criterion 3 – expected ArkErrors");
console.log("✅ Criterion 3: rejected (instanceof type.errors =", r3 instanceof type.errors, ")");

// Criterion 4: expression reflects only "int" | "raw"
console.log("Schema expression:", PayloadSchema.expression);
console.log("✅ All criteria passed");
EOF

